<template><view class="page"><view class="head"><text class="back" @tap="back">‹</text><view><text class="title">多人聚餐</text><text class="sub">一起点菜，轻松 AA</text></view></view>
<view class="start" v-if="!room"><view class="hero"><text class="hero-mark">聚</text><text class="hero-title">今天一起吃什么？</text><text class="hero-sub">创建房间后分享给好友，所有人都能共同点菜</text></view><input class="input" v-model="title" placeholder="给聚餐起个名字"/><view class="primary" @tap="create">创建聚餐房间</view><view class="or">或加入好友的房间</view><view class="join"><input v-model="joinCode" maxlength="6" placeholder="6位房间码"/><text @tap="join">加入</text></view><view style="height:72rpx;margin-top:14rpx;display:flex;align-items:center;justify-content:center;color:#22bf91;font-weight:800" @tap="scanJoin">▣ 扫码加入</view></view>
<scroll-view class="body" scroll-y v-else><view class="room-card"><view><text class="room-title">{{room.title}}</text><text class="room-code">房间码 {{room.roomCode}}</text></view><button open-type="share" class="share">分享加入</button></view><view class="members"><text class="section-title">聚餐成员（{{room.members.length}}）</text><scroll-view scroll-x class="member-scroll"><view class="member" v-for="m in room.members" :key="m.userId"><image :src="m.avatar||'/static/kitchen_avatar.png'"/><text>{{m.nickname}}</text></view></scroll-view></view>
<view class="bill"><view><text>聚餐总计</text><text class="money">￥{{room.total||0}}</text></view><view><text>每人 AA</text><text class="aa">￥{{room.aa||0}}</text></view></view><view class="section-row"><text class="section-title">共同点菜</text><text @tap="refresh">刷新</text></view><view class="items" v-if="room.items.length"><view class="item" v-for="i in room.items" :key="i.dishId"><image :src="i.cover||'/static/onion_chicken.png'"/><view class="item-copy"><text>{{i.dishName}}</text><text>￥{{i.price}} × {{i.quantity}} · {{i.addedBy}}添加</text></view><text>￥{{i.subtotal}}</text></view></view><view class="empty" v-else>还没人点菜</view>
<view class="section-row"><text class="section-title">加菜</text><text>点击 + 加入房间</text></view><view class="dish-grid"><view class="dish" v-for="d in dishes" :key="d.id"><image :src="d.cover||'/static/onion_chicken.png'"/><text class="dish-name">{{d.dishName}}</text><view><text>￥{{d.virtualPrice||0}}</text><text class="plus" @tap="add(d)">+</text></view></view></view><view class="space"></view></scroll-view></view></template>
<script>import{apiGroupCreate,apiGroupJoin,apiGroupDetail,apiGroupAddItem}from'@/api/social.js';import{apiDishList}from'@/api/dish.js';import{ensureLogin}from'@/utils/login.js';export default{data(){return{title:'周末聚餐',joinCode:'',room:null,dishes:[]}},onLoad(o){this.loadDishes();if(o.code){this.joinCode=o.code;this.join()}},onShareAppMessage(){return{title:(this.room&&this.room.title)||'来一起点菜',path:'/pages/group-dining/group-dining?code='+(this.room?this.room.roomCode:'')}},methods:{async create(){try{await ensureLogin();let r=await apiGroupCreate({title:this.title});await this.open(r.data.id)}catch(e){}},async join(){if(!this.joinCode.trim())return;try{await ensureLogin();let r=await apiGroupJoin({roomCode:this.joinCode.trim()});await this.open(r.data.id)}catch(e){}},scanJoin(){uni.scanCode({scanType:['qrCode'],success:r=>{let m=String(r.result||'').match(/(?:code=)?([A-Z0-9]{6})$/i);if(m){this.joinCode=m[1].toUpperCase();this.join()}else uni.showToast({title:'未识别到有效房间码',icon:'none'})}})},async open(id){let r=await apiGroupDetail(id);this.room=r.data},async refresh(){if(this.room)await this.open(this.room.id)},async add(d){try{await apiGroupAddItem({roomId:this.room.id,dishId:d.id,quantity:1});await this.refresh();uni.showToast({title:'已加入共同菜单',icon:'none'})}catch(e){}},async loadDishes(){try{let r=await apiDishList({pageNum:1,pageSize:30});this.dishes=r.rows||[]}catch(e){}},back(){uni.navigateBack()}}}</script>
<style>.page{min-height:100vh;background:#f5faf8;color:#202725}.head{height:170rpx;padding:calc(34rpx + env(safe-area-inset-top)) 28rpx 22rpx;display:flex;align-items:flex-end;background:linear-gradient(135deg,#dbfaf1,#f7fffc);box-sizing:border-box}.back{width:66rpx;height:66rpx;border-radius:50%;background:#fff;text-align:center;font-size:54rpx;line-height:58rpx;margin-right:18rpx}.title{display:block;font-size:38rpx;font-weight:900}.sub{font-size:22rpx;color:#819089}.start{padding:28rpx}.hero{height:300rpx;border-radius:30rpx;background:#24342f;color:#fff;display:flex;flex-direction:column;align-items:center;justify-content:center}.hero-mark{width:78rpx;height:78rpx;border-radius:25rpx;background:#35cda4;text-align:center;line-height:78rpx;font-size:36rpx;font-weight:900}.hero-title{font-size:35rpx;font-weight:900;margin-top:20rpx}.hero-sub{font-size:23rpx;color:#bad0c8;margin-top:12rpx}.input,.join{height:82rpx;margin-top:24rpx;padding:0 24rpx;border-radius:18rpx;background:#fff;box-sizing:border-box}.primary{height:84rpx;margin-top:18rpx;border-radius:42rpx;background:#35cda4;color:#fff;display:flex;align-items:center;justify-content:center;font-size:30rpx;font-weight:900}.or{text-align:center;margin:28rpx;color:#96a29d;font-size:24rpx}.join{display:flex;align-items:center}.join input{flex:1}.join text{color:#22bf91;font-weight:900}.body{height:calc(100vh - 170rpx)}.room-card{margin:24rpx;padding:26rpx;border-radius:24rpx;background:#24342f;color:#fff;display:flex;align-items:center;justify-content:space-between}.room-title{display:block;font-size:32rpx;font-weight:900}.room-code{display:block;margin-top:8rpx;color:#b9cec7;font-size:23rpx}.share{margin:0;padding:0 24rpx;height:62rpx;line-height:62rpx;border-radius:32rpx;background:#35cda4;color:#fff;font-size:24rpx}.members,.items,.bill{margin:0 24rpx 18rpx;padding:22rpx;border-radius:22rpx;background:#fff}.section-title{font-size:29rpx;font-weight:900}.member-scroll{white-space:nowrap;margin-top:18rpx}.member{display:inline-flex;width:100rpx;flex-direction:column;align-items:center}.member image{width:62rpx;height:62rpx;border-radius:50%}.member text{width:96rpx;margin-top:6rpx;font-size:20rpx;text-align:center;overflow:hidden}.bill{display:flex;justify-content:space-around;text-align:center}.bill view{display:flex;flex-direction:column}.money,.aa{margin-top:8rpx;font-size:35rpx;font-weight:900}.aa{color:#22bf91}.section-row{padding:20rpx 30rpx;display:flex;justify-content:space-between;align-items:center}.section-row>text:last-child{font-size:22rpx;color:#7e8d87}.item{height:112rpx;display:flex;align-items:center;border-bottom:1rpx solid #edf2f0}.item image{width:82rpx;height:82rpx;border-radius:12rpx}.item-copy{flex:1;margin-left:16rpx;display:flex;flex-direction:column}.item-copy text:first-child{font-weight:900}.item-copy text:last-child{font-size:21rpx;color:#8e9a95;margin-top:8rpx}.empty{margin:0 24rpx;padding:55rpx;text-align:center;background:#fff;border-radius:22rpx;color:#97a29e}.dish-grid{padding:0 24rpx;display:grid;grid-template-columns:1fr 1fr;gap:16rpx}.dish{padding:14rpx;border-radius:20rpx;background:#fff}.dish image{width:100%;height:190rpx;border-radius:14rpx}.dish-name{display:block;margin:12rpx 4rpx;font-weight:900}.dish>view{display:flex;justify-content:space-between;align-items:center;color:#22bf91}.plus{width:46rpx;height:46rpx;border-radius:50%;background:#35cda4;color:#fff;text-align:center;line-height:44rpx;font-size:36rpx}.space{height:80rpx}</style>
